好的，以下是 STM32CubeIDE 1.8.0 版本的 TCS3200.c 文件示例代码：

#include “TCS3200.h”

/* 定义 TCS3200 的 GPIO 引脚和定时器、PWM 的实例名称 /
TIM_HandleTypeDef htim2;
TIM_OC_InitTypeDef sConfig;
GPIO_InitTypeDef GPIO_InitStruct;

/ TCS3200 初始化函数 /
void TCS3200_Init(void)
{
/ 完成 GPIO 配置 /
TCS3200_GPIO_Init();

/ 完成定时器初始化 /
TCS3200_Timer_Init();

/ 完成 PWM 初始化 /
TCS3200_PWM_Init();

/ 配置 TCS3200 的频率 /
TCS3200_SetFreq(2);
}

/ TCS3200 GPIO 初始化函数 /
void TCS3200_GPIO_Init(void)
{
/ 使能 GPIO 时钟 /
__HAL_RCC_GPIOA_CLK_ENABLE();

/ 配置 TCS3200 的 S0、S1 引脚为推挽输出 /
GPIO_InitStruct.Pin = TCS3200_S0_PIN | TCS3200_S1_PIN;
GPIO_InitStruct.Mode = GPIO_MODE_OUTPUT_PP;
GPIO_InitStruct.Speed = GPIO_SPEED_FREQ_HIGH;
HAL_GPIO_Init(TCS3200_GPIO_PORT, &GPIO_InitStruct);

/ 配置 TCS3200 的 OUT 引脚为上拉输入 /
GPIO_InitStruct.Pin = TCS3200_OUT_PIN;
GPIO_InitStruct.Mode = GPIO_MODE_INPUT;
GPIO_InitStruct.Pull = GPIO_PULLUP;
HAL_GPIO_Init(TCS3200_GPIO_PORT, &GPIO_InitStruct);
}

/ TCS3200 定时器初始化函数 /
void TCS3200_Timer_Init(void)
{
/ 定时器时钟使能 /
__HAL_RCC_TIM2_CLK_ENABLE();

/ 定时器 2 管脚配置，输出 PWM /
GPIO_InitStruct.Pin = TCS3200_G_PIN;
GPIO_InitStruct.Mode = GPIO_MODE_AF_PP;
GPIO_InitStruct.Speed = GPIO_SPEED_FREQ_LOW;
HAL_GPIO_Init(TCS3200_GPIO_PORT, &GPIO_InitStruct);

/ 定时器 2 配置 /
htim2.Instance = TIM2;
htim2.Init.Prescaler = 0;
htim2.Init.CounterMode = TIM_COUNTERMODE_UP;
htim2.Init.Period = TCS3200_TIMER_COUNTS - 1;
htim2.Init.ClockDivision = TIM_CLOCKDIVISION_DIV1;
if (HAL_TIM_Base_Init(&htim2) != HAL_OK)
{
/ 定时器初始化错误处理代码 /
Error_Handler();
}

/ TIM2 PWM 处理单元配置 /
sConfig.OCMode = TIM_OCMODE_PWM1;
sConfig.Pulse = 0;
sConfig.OCPolarity = TIM_OCPOLARITY_HIGH;
sConfig.OCFastMode = TIM_OCFAST_DISABLE;
if (HAL_TIM_PWM_ConfigChannel(&htim2, &sConfig, TIM_CHANNEL_1) != HAL_OK)
{
/ PWM 单元配置错误处理代码 /
Error_Handler();
}
}

/ TCS3200 PWM 初始化函数 /
void TCS3200_PWM_Init(void)
{
/ 使能 TIM2 PWM 输出 /
HAL_TIM_PWM_Start(&htim2, TIM_CHANNEL_1);
}

/ 配置 TCS3200 的频率 /
void TCS3200_SetFreq(uint16_t freq)
{
/ 计算定时器的预分频值和计数重载值 /
uint16_t prescaler = (uint16_t)(SystemCoreClock / (TCS3200_TIMER_PRESCALER * (uint32_t)freq)) - 1;
uint16_t period = (uint16_t)(TCS3200_TIMER_COUNTS / (prescaler + 1)) - 1;

/ 配置 TCS3200 的 S0、S1 引脚切换频率 /
if (freq == 2)
{
HAL_GPIO_WritePin(TCS3200_GPIO_PORT, TCS3200_S0_PIN, GPIO_PIN_RESET);
HAL_GPIO_WritePin(TCS3200_GPIO_PORT, TCS3200_S1_PIN, GPIO_PIN_RESET);
}
else if (freq == 20)
{
HAL_GPIO_WritePin(TCS3200_GPIO_PORT, TCS3200_S0_PIN, GPIO_PIN_SET);
HAL_GPIO_WritePin(TCS3200_GPIO_PORT, TCS3200_S1_PIN, GPIO_PIN_RESET);
}
else if (freq == 100)
{
HAL_GPIO_WritePin(TCS3200_GPIO_PORT, TCS3200_S0_PIN, GPIO_PIN_RESET);
HAL_GPIO_WritePin(TCS3200_GPIO_PORT, TCS3200_S1_PIN, GPIO_PIN_SET);
}
else if (freq == 1000)
{
HAL_GPIO_WritePin(TCS3200_GPIO_PORT, TCS3200_S0_PIN, GPIO_PIN_SET);
HAL_GPIO_WritePin(TCS3200_GPIO_PORT, TCS3200_S1_PIN, GPIO_PIN_SET);
}
else
{
/ 频率不在支持的范围内，错误处理代码 /
Error_Handler();
}

/ 配置定时器 2 的预分频值和计数重载值 /
htim2.Init.Prescaler = prescaler;
htim2.Init.Period = period;
if (HAL_TIM_Base_Init(&htim2) != HAL_OK)
{
/ 定时器初始化错误处理代码 */
Error_Handler();
}
