#include "main.h"
#include "TCS3200.h"

int main(void)
{
  HAL_Init();
  SystemClock_Config();

  TCS3200_Init();

  while (1)
  {
    // 获取当前颜色
    uint16_t red = TCS3200_GetColor(TCS3200_COLOR_RED);
    uint16_t green = TCS3200_GetColor(TCS3200_COLOR_GREEN);
    uint16_t blue = TCS3200_GetColor(TCS3200_COLOR_BLUE);

    // 在串口上输出颜色值
    char buffer[50];
    sprintf(buffer, "R:%d G:%d B:%d\r\n", red, green, blue);
    HAL_UART_Transmit(&huart1, (uint8_t *)buffer, strlen(buffer), HAL_MAX_DELAY);

    HAL_Delay(500);
  }
}

其中，TCS3200_GetColor() 函数可以根据具体应用场景进行定制，实现颜色传感器的读取功能。该函数的具体实现要根据 TCS3200 的工作原理进行设计。

